def extract_key_from_nested_json(data, key_to_extract):
    """
    Belirli bir anahtarın (key) tüm değerlerini iç içe geçmiş JSON benzeri bir yapıdan çıkarır.
    """
    extracted_values = []

    if isinstance(data, dict):
        for key, value in data.items():
            if key == key_to_extract:
                extracted_values.append(value)
            # İç içe geçmiş sözlükler veya listeler içinde özyinelemeli olarak arama yap
            if isinstance(value, (dict, list)):
                extracted_values.extend(extract_key_from_nested_json(value, key_to_extract))
    elif isinstance(data, list):
        for item in data:
            # Listenin öğeleri içinde özyinelemeli olarak arama yap
            if isinstance(item, (dict, list)):
                extracted_values.extend(extract_key_from_nested_json(item, key_to_extract))

    return extracted_values
